on_write:
let res = #{ action: "Allow" };
if !payload.contains("class_name") {
    res.action = "Reject";
    res.reason = "Object-oriented paradigm requires a class_name definition";
}
res

on_read:
let res = #{ payload: payload };
if payload.class_name == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
